local LCacheMgr = LxClass("LCacheMgr", nil)
-----------------------------------------------------------------
function LCacheMgr:LCacheMgr()
	self._cacheMap = {}
	self._checkTimerKey = "_checkTimerKey"

	local timer = self._timer
	if not timer then
		timer = LxTimer:New()
		self._timer = timer
	end
	timer:TimerRemoveByKey(self._checkTimerKey)
	timer:TimerCreate(self._checkTimerKey,function ()
		self:CheckDestroy()
	end,10,true,-1)
end

------------------------------------------------------------------
function LCacheMgr:GetCache(cacheKey, getFunc, arg1, arg2)
	local cacheMap = self._cacheMap
	local objList = cacheMap[cacheKey]
	if not objList then
		objList = {}
		cacheMap[cacheKey] = objList
	end
	if #objList == 0 then
		return getFunc(arg1,arg2)
	end
	return table.remove(objList)
end

