function LCacheMgr:ReleaseCache(cacheKey, cache)
	local cacheMap = self._cacheMap
	local objList = cacheMap[cacheKey]
	if not objList then
		objList = {}
		cacheMap[cacheKey] = objList
	end
	cache:SetTime(Time.unscaledTime)
	table.insert(objList, cache)
end

function LCacheMgr:CheckDestroy()
	local hudItem = nil
	local curTime = Time.unscaledTime
	for k,v in pairs(self._cacheMap) do
		local cnt = #v
		for k1=cnt,1,-1 do
			hudItem = v[k1]
			if curTime - hudItem:GetTime() > 10 then
				hudItem:Destroy()
				table.remove(v,k1)
			end
		end
	end
end

-----------------------------------------------------------------
function LCacheMgr:Destroy()
	if self._isDestroy then
		return
	end

	local timer = self._timer
	if timer then
		timer:Destroy()
		self._timer = nil
	end

	for _,objList in pairs(self._cacheMap) do
		for k,v in ipairs(objList) do
			v:Destroy()
		end
	end
	self._cacheMap = nil
	self._isDestroy = true
end

